// ============================================================
// SELECTION LOGIC
// ============================================================

// Each "send" gets a unique slot number based on date. Twice weekly = 2 slots/week.
// Monday send: slot = weekNumber * 2
// Thursday send: slot = weekNumber * 2 + 1
// We compute slot from the actual send date so it works regardless of which day it fires.
function getSlotNumber(): number {
  // Use day-of-year / 3.5 to get a unique slot for every Monday and Thursday
  const now = new Date();
  const start = new Date(now.getFullYear(), 0, 0);
  const diff = now.getTime() - start.getTime();
  const dayOfYear = Math.floor(diff / (1000 * 60 * 60 * 24));
  // Roughly: every 3-4 days = new slot
  return Math.floor(dayOfYear / 3.5) + (now.getFullYear() * 100);
}

function getCaseForUser(profession: string, slot: number): Case {
  const eligible = CASES.filter(c => c.professions.includes("all") || c.professions.includes(profession));
  const profHash = profession.split("").reduce((a, c) => a + c.charCodeAt(0), 0);
  return eligible[(slot + profHash) % eligible.length];
}

function getOtherCases(profession: string, slot: number, exclude: string, count: number): Case[] {
  const eligible = CASES.filter(c =>
    (c.professions.includes("all") || c.professions.includes(profession)) && c.id !== exclude
  );
  const profHash = profession.split("").reduce((a, c) => a + c.charCodeAt(0), 0);
  const out: Case[] = [];
  // Pick spaced-apart cases to feel curated, not random
  for (let i = 1; i <= count; i++) {
    const idx = (slot + profHash + i * 47) % eligible.length;
    out.push(eligible[idx]);
  }
  return out;
}

function getPuzzleForSlot(slot: number): Puzzle {
  return PUZZLES[slot % PUZZLES.length];
}

function getModuleForSlot(slot: number): ModuleItem {
  // Offset so module rotates independently from puzzle
  return MODULES[(slot + 7) % MODULES.length];
}

