// ============================================================
// SEND
// ============================================================

async function sendEmail(to: string, subject: string, html: string): Promise<boolean> {
  try {
    const res = await fetch("https://api.resend.com/emails", {
      method: "POST",
      headers: { "Authorization": `Bearer ${RESEND_API_KEY}`, "Content-Type": "application/json" },
      body: JSON.stringify({ from: FROM_EMAIL, reply_to: REPLY_TO, to, subject, html })
    });
    const data = await res.json();
    if (!res.ok) { console.error(`Email failed to ${to}:`, data); return false; }
    console.log(`Sent to ${to}: ${data.id}`);
    return true;
  } catch (e) {
    console.error(`Error for ${to}:`, e);
    return false;
  }
}

Deno.serve(async (req) => {
  let testEmail = null;
  if (req.method === "POST") {
    try { const b = await req.json(); testEmail = b?.test_email || null; } catch(e) {}
  }

  const supabase = createClient(SUPABASE_URL, SUPABASE_SERVICE_KEY);

  // Compute slot once per send — Monday and Thursday will produce different slots
  const slot = getSlotNumber();
  const weeklyPuzzle = getPuzzleForSlot(slot);
  const weeklyModule = getModuleForSlot(slot);

  let users: any[] = [];
  if (testEmail) {
    users = [{
      email: testEmail, full_name: "Test User",
      streak_days: 5, total_cases_completed: 12,
      engagement_status: "active", profession: "medicine"
    }];
  } else {
    const { data, error } = await supabase.from("weekly_email_eligible").select("*");
    if (error) return new Response(JSON.stringify({ error: error.message }), { status: 500 });
    users = data || [];
  }

  let sent = 0, failed = 0;
  for (const user of users) {
    const profession = user.profession_id || "all";
    const wc = getCaseForUser(profession, slot);
    const otherCases = getOtherCases(profession, slot, wc.id, 3);
    const subject = `This week: ${weeklyPuzzle.title}`;

    const success = await sendEmail(
      user.email,
      subject,
      buildEmailHtml({ ...user, profession }, wc, weeklyPuzzle, weeklyModule, otherCases)
    );
    if (success) sent++; else failed++;
    await new Promise(r => setTimeout(r, 100));
  }

  return new Response(
    JSON.stringify({ success: true, sent, failed, total: users.length, slot }),
    { headers: { "Content-Type": "application/json" } }
  );
});
